import { useState, useCallback } from "react";

// ── Embedded assets ──────────────────────────────────────────────
const FLOWERS_IMG = "data:image/png;base64,";
const NOVA_LOGO   = "data:image/jpeg;base64,";

// ── Types ────────────────────────────────────────────────────────
type Mode = "dark" | "light";

// ── Suggestion chips ─────────────────────────────────────────────
const CHIPS = ["Antara communities", "Care services", "Book a visit"];

// ── Icons ────────────────────────────────────────────────────────
const MicIcon = ({ color }: { color: string }) => (
  <svg width="15" height="15" viewBox="0 0 24 24" fill="none"
    stroke={color} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <path d="M12 2a3 3 0 0 1 3 3v7a3 3 0 0 1-6 0V5a3 3 0 0 1 3-3z" />
    <path d="M19 10v2a7 7 0 0 1-14 0v-2" />
    <line x1="12" y1="19" x2="12" y2="22" />
    <line x1="8" y1="22" x2="16" y2="22" />
  </svg>
);

const SendIcon = () => (
  <svg width="15" height="15" viewBox="0 0 24 24" fill="none"
    stroke="white" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
    <line x1="12" y1="19" x2="12" y2="5" />
    <polyline points="5 12 12 5 19 12" />
  </svg>
);

const MinimizeIcon = () => (
  <svg width="22" height="4" viewBox="0 0 22 4" fill="none">
    <line x1="1" y1="2" x2="21" y2="2" stroke="#d44a28" strokeWidth="2.5" strokeLinecap="round" />
  </svg>
);

// ── Styles helper ────────────────────────────────────────────────
const S = {
  // scene
  scene: (mode: Mode): React.CSSProperties => ({
    width: 340,
    height: 680,
    borderRadius: 28,
    position: "relative",
    overflow: "hidden",
    background: mode === "dark" ? "#0f1410" : "#f4f0ea",
    border: `1.5px solid ${mode === "dark" ? "#1e2820" : "#d8d2c8"}`,
    boxShadow: mode === "dark"
      ? "0 20px 60px rgba(0,0,0,0.5)"
      : "0 20px 60px rgba(0,0,0,0.12)",
  }),

  // fake website lines
  fakeLine: (mode: Mode, width: string, marginTop?: number): React.CSSProperties => ({
    height: 10,
    width,
    borderRadius: 4,
    marginBottom: 10,
    marginTop,
    background: mode === "dark" ? "rgba(255,255,255,0.06)" : "rgba(0,0,0,0.07)",
  }),
  fakeTitle: (mode: Mode): React.CSSProperties => ({
    height: 18,
    width: "60%",
    borderRadius: 4,
    marginBottom: 16,
    background: mode === "dark" ? "rgba(255,255,255,0.06)" : "rgba(0,0,0,0.07)",
  }),
  fakeImg: (mode: Mode): React.CSSProperties => ({
    width: "100%",
    height: 120,
    borderRadius: 12,
    marginBottom: 16,
    background: mode === "dark" ? "rgba(255,255,255,0.04)" : "rgba(0,0,0,0.06)",
  }),

  // bubble
  bubble: (mode: Mode): React.CSSProperties => ({
    position: "absolute",
    bottom: 24,
    right: 20,
    width: 58,
    height: 58,
    borderRadius: "50%",
    cursor: "pointer",
    zIndex: 100,
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    background: mode === "dark" ? "#141c14" : "#fff",
    border: `1.5px solid ${mode === "dark" ? "rgba(0,180,80,0.15)" : "rgba(180,80,40,0.12)"}`,
    boxShadow: mode === "dark"
      ? "0 6px 24px rgba(0,180,80,0.2), 0 2px 8px rgba(0,0,0,0.4)"
      : "0 6px 24px rgba(180,80,40,0.22), 0 2px 8px rgba(0,0,0,0.1)",
    animation: "bubblePop 0.4s cubic-bezier(.34,1.56,.64,1)",
  }),

  // panel
  panel: (mode: Mode): React.CSSProperties => ({
    position: "absolute",
    inset: 0,
    borderRadius: 28,
    zIndex: 90,
    display: "flex",
    flexDirection: "column",
    overflow: "hidden",
    background: mode === "dark"
      ? "linear-gradient(170deg,#080d14 0%,#0d1520 30%,#0a1a12 60%,#061008 100%)"
      : "linear-gradient(170deg,#fdfaf5 0%,#f5f0e8 35%,#ede8df 100%)",
    animation: "panelOpen 0.38s cubic-bezier(.34,1.3,.64,1)",
  }),

  // orb
  orb: (mode: Mode): React.CSSProperties => ({
    position: "absolute",
    top: "38%",
    left: "50%",
    transform: "translate(-50%,-50%)",
    width: 260,
    height: 260,
    borderRadius: "50%",
    background: mode === "dark"
      ? "radial-gradient(circle,rgba(0,200,100,0.12) 0%,transparent 70%)"
      : "radial-gradient(circle,rgba(220,100,60,0.09) 0%,transparent 70%)",
    animation: "pulse 4s ease-in-out infinite",
    pointerEvents: "none",
  }),

  // topbar
  topbar: (): React.CSSProperties => ({
    display: "flex",
    alignItems: "center",
    justifyContent: "space-between",
    padding: "20px 20px 0",
    flexShrink: 0,
    position: "relative",
    zIndex: 10,
  }),

  minimizeBtn: (): React.CSSProperties => ({
    width: 32,
    height: 32,
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    cursor: "pointer",
    opacity: 0.75,
  }),

  // hero
  hero: (): React.CSSProperties => ({
    flex: 1,
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    justifyContent: "center",
    textAlign: "center",
    padding: "0 32px",
    position: "relative",
    zIndex: 5,
  }),

  heroTitle: (mode: Mode): React.CSSProperties => ({
    fontFamily: "'Kumbh Sans', sans-serif",
    fontSize: 24,
    fontWeight: 600,
    letterSpacing: -0.3,
    marginBottom: 10,
    lineHeight: 1.15,
    color: mode === "dark" ? "#ffffff" : "#1a1208",
  }),

  heroSubtitle: (mode: Mode): React.CSSProperties => ({
    fontFamily: "'DM Sans', sans-serif",
    fontSize: 14,
    fontWeight: 300,
    lineHeight: 1.55,
    color: mode === "dark" ? "rgba(255,255,255,0.45)" : "rgba(60,40,20,0.52)",
  }),

  // bottom
  bottom: (): React.CSSProperties => ({
    padding: "0 16px 20px",
    flexShrink: 0,
    position: "relative",
    zIndex: 10,
  }),

  chip: (mode: Mode): React.CSSProperties => ({
    flexShrink: 0,
    padding: "7px 12px",
    borderRadius: 100,
    fontSize: 11,
    fontWeight: 400,
    whiteSpace: "nowrap",
    fontFamily: "'DM Sans', sans-serif",
    background: mode === "dark" ? "rgba(255,255,255,0.06)" : "rgba(180,80,40,0.07)",
    border: `1px solid ${mode === "dark" ? "rgba(255,255,255,0.09)" : "rgba(180,80,40,0.15)"}`,
    color: mode === "dark" ? "rgba(255,255,255,0.5)" : "rgba(120,50,20,0.75)",
    cursor: "pointer",
  }),

  inputRow: (mode: Mode): React.CSSProperties => ({
    display: "flex",
    alignItems: "center",
    gap: 8,
    borderRadius: 14,
    padding: "5px 5px 5px 14px",
    backdropFilter: "blur(20px)",
    background: mode === "dark" ? "rgba(255,255,255,0.06)" : "rgba(255,255,255,0.8)",
    border: `1px solid ${mode === "dark" ? "rgba(255,255,255,0.1)" : "rgba(180,80,40,0.15)"}`,
    boxShadow: mode === "light" ? "0 2px 12px rgba(0,0,0,0.06)" : "none",
  }),

  voiceBtn: (mode: Mode): React.CSSProperties => ({
    width: 36,
    height: 36,
    borderRadius: 10,
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    cursor: "pointer",
    background: mode === "dark" ? "rgba(255,255,255,0.08)" : "rgba(180,80,40,0.08)",
    border: `1px solid ${mode === "dark" ? "rgba(255,255,255,0.12)" : "rgba(180,80,40,0.18)"}`,
  }),

  sendBtn: (mode: Mode): React.CSSProperties => ({
    width: 36,
    height: 36,
    borderRadius: 10,
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    cursor: "pointer",
    background: mode === "dark"
      ? "linear-gradient(135deg,#00c864,#00a052)"
      : "linear-gradient(135deg,#d44a28,#b83a1e)",
    boxShadow: mode === "dark"
      ? "0 4px 12px rgba(0,200,100,0.3)"
      : "0 4px 12px rgba(200,70,40,0.3)",
  }),

  divider: (mode: Mode): React.CSSProperties => ({
    width: 1,
    height: 20,
    background: mode === "dark" ? "rgba(255,255,255,0.1)" : "rgba(0,0,0,0.1)",
    flexShrink: 0,
  }),
};

// ── Widget component ─────────────────────────────────────────────
function AntaraWidget({ mode }: { mode: Mode }) {
  const [expanded, setExpanded] = useState(false);

  const expand   = useCallback(() => setExpanded(true),  []);
  const minimize = useCallback(() => setExpanded(false), []);

  return (
    <div style={S.scene(mode)}>
      {/* Fake website skeleton */}
      <div style={{ position: "absolute", inset: 0, padding: "28px 24px" }}>
        <div style={S.fakeTitle(mode)} />
        <div style={S.fakeImg(mode)} />
        <div style={S.fakeLine(mode, "90%")} />
        <div style={S.fakeLine(mode, "70%")} />
        <div style={S.fakeLine(mode, "80%")} />
        <div style={S.fakeLine(mode, "65%", 14)} />
        <div style={S.fakeLine(mode, "85%")} />
      </div>

      {/* Minimized bubble */}
      {!expanded && (
        <div style={S.bubble(mode)} onClick={expand} role="button" aria-label="Open Antara AI">
          {/* Pulse ring */}
          <div style={{
            position: "absolute", inset: -6, borderRadius: "50%",
            border: `1.5px solid ${mode === "dark" ? "rgba(0,200,80,0.3)" : "rgba(180,80,40,0.3)"}`,
            animation: "ringPulse 2.5s ease-out infinite",
          }} />
          <img
            src={FLOWERS_IMG}
            alt="Antara AI"
            style={{
              height: 36, width: "auto",
              filter: "drop-shadow(0 2px 6px rgba(180,80,40,0.3))",
            }}
          />
        </div>
      )}

      {/* Expanded panel */}
      {expanded && (
        <div style={S.panel(mode)}>
          {/* Background orb */}
          <div style={S.orb(mode)} />

          {/* Top bar */}
          <div style={S.topbar()}>
            <img
              src={NOVA_LOGO}
              alt="NOVA"
              style={{
                height: 18,
                filter: mode === "light" ? "invert(1)" : "none",
              }}
            />
            <div
              style={S.minimizeBtn()}
              onClick={minimize}
              role="button"
              aria-label="Minimize"
            >
              <MinimizeIcon />
            </div>
          </div>

          {/* Hero */}
          <div style={S.hero()}>
            <div style={{ marginBottom: 20, animation: "floatOrb 5s ease-in-out infinite" }}>
              <img
                src={FLOWERS_IMG}
                alt="Antara"
                style={{
                  height: 60,
                  width: "auto",
                  filter: mode === "dark"
                    ? "drop-shadow(0 6px 18px rgba(220,100,60,0.38))"
                    : "drop-shadow(0 6px 18px rgba(180,60,40,0.22))",
                }}
              />
            </div>
            <div style={S.heroTitle(mode)}>I'm Antara AI</div>
            <div style={S.heroSubtitle(mode)}>
              Ask me anything<br />about senior living
            </div>
          </div>

          {/* Bottom: chips + input */}
          <div style={S.bottom()}>
            <div className="chips-row" style={{ display: "flex", gap: 7, overflowX: "auto", marginBottom: 10, paddingBottom: 2, scrollbarWidth: "none", msOverflowStyle: "none" }}>
              {CHIPS.map((chip) => (
                <div key={chip} style={S.chip(mode)}>{chip}</div>
              ))}
            </div>
            <div style={S.inputRow(mode)}>
              <div style={{
                flex: 1,
                fontFamily: "'DM Sans', sans-serif",
                fontSize: 13,
                fontWeight: 300,
                color: mode === "dark" ? "rgba(255,255,255,0.4)" : "rgba(80,50,20,0.5)",
              }}>
                Ask about senior living...
              </div>
              <div style={{ display: "flex", alignItems: "center", gap: 5, flexShrink: 0 }}>
                <div style={S.divider(mode)} />
                <div style={S.voiceBtn(mode)} role="button" aria-label="Voice note">
                  <MicIcon color={mode === "dark" ? "rgba(255,255,255,0.65)" : "rgba(150,70,30,0.7)"} />
                </div>
                <div style={S.sendBtn(mode)} role="button" aria-label="Send">
                  <SendIcon />
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ── Toggle ───────────────────────────────────────────────────────
function ModeToggle({ mode, onToggle }: { mode: Mode; onToggle: () => void }) {
  const isDark = mode === "dark";
  return (
    <div style={{
      display: "flex", alignItems: "center", gap: 12,
      background: "#fff", border: "1px solid #ddd", borderRadius: 100,
      padding: "6px 8px", boxShadow: "0 2px 12px rgba(0,0,0,0.08)",
    }}>
      <span style={{ fontFamily: "'DM Sans',sans-serif", fontSize: 13, fontWeight: 500, color: "#666", padding: "0 4px" }}>
        ☀️ Light
      </span>
      <div
        onClick={onToggle}
        role="switch"
        aria-checked={isDark}
        style={{
          width: 52, height: 28, borderRadius: 100, position: "relative",
          cursor: "pointer", transition: "background 0.35s",
          background: isDark ? "#222" : "#f0f0f0",
          border: isDark ? "none" : "1px solid #ddd",
        }}
      >
        <div style={{
          position: "absolute", top: 3, left: 3,
          width: 22, height: 22, borderRadius: "50%",
          transition: "transform 0.35s cubic-bezier(.4,0,.2,1)",
          transform: isDark ? "translateX(24px)" : "translateX(0)",
          background: isDark ? "#333" : "#fff",
          boxShadow: "0 1px 4px rgba(0,0,0,0.2)",
          display: "flex", alignItems: "center", justifyContent: "center",
          fontSize: 12,
        }}>
          {isDark ? "🌙" : "☀️"}
        </div>
      </div>
      <span style={{ fontFamily: "'DM Sans',sans-serif", fontSize: 13, fontWeight: 500, color: "#666", padding: "0 4px" }}>
        🌙 Dark
      </span>
    </div>
  );
}

// ── App ──────────────────────────────────────────────────────────
export default function App() {
  const [mode, setMode] = useState<Mode>("dark");

  return (
    <>
      {/* Google Fonts */}
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@300;400;500;600&family=Kumbh+Sans:wght@300;400;600;700&display=swap');

        * { margin: 0; padding: 0; box-sizing: border-box; }

        body {
          background: #e0dbd4;
          min-height: 100vh;
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          gap: 40px;
          padding: 40px 20px;
          font-family: 'DM Sans', sans-serif;
        }

        @keyframes bubblePop {
          0%   { transform: scale(0.5); opacity: 0; }
          100% { transform: scale(1);   opacity: 1; }
        }
        @keyframes panelOpen {
          0%   { transform: scale(0.85) translateY(20px); opacity: 0; }
          100% { transform: scale(1)    translateY(0);    opacity: 1; }
        }
        @keyframes ringPulse {
          0%   { opacity: 0.8; transform: scale(1);   }
          100% { opacity: 0;   transform: scale(1.4); }
        }
        @keyframes pulse {
          0%,100% { transform: translate(-50%,-50%) scale(1);   opacity: 0.8; }
          50%     { transform: translate(-50%,-50%) scale(1.1); opacity: 1;   }
        }
        @keyframes floatOrb {
          0%,100% { transform: translateY(0px);  }
          50%     { transform: translateY(-7px); }
        }

        /* Hide scrollbar on chips row */
        .chips-row::-webkit-scrollbar { display: none; }
      `}</style>

      <ModeToggle mode={mode} onToggle={() => setMode(m => m === "dark" ? "light" : "dark")} />

      <div style={{ display: "flex", gap: 48, flexWrap: "wrap", justifyContent: "center", alignItems: "flex-end" }}>
        <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 14 }}>
          <span style={{
            fontFamily: "'Kumbh Sans',sans-serif", fontSize: 11,
            fontWeight: 600, letterSpacing: "2.5px", textTransform: "uppercase", color: "#999",
          }}>
            {mode === "dark" ? "Dark Mode" : "Light Mode"}
          </span>
          <AntaraWidget mode={mode} />
        </div>
      </div>
    </>
  );
}
